// toString nümunəsi
const num = 42;
console.log(num.toString()); // '42'
console.log(num.toString(2)); // '101010' (ikili)
console.log(num.toString(16)); // '2a' (onaltılıq)
// Çıxış:
// 42
// 101010
// 2a

// toFixed nümunəsi
const price = 19.999;
console.log(price.toFixed(2)); // '20.00'
console.log(price.toFixed(1)); // '20.0'
console.log(price.toFixed(0)); // '20'
// Çıxış:
// 20.00
// 20.0
// 20

// parseInt nümunəsi
console.log(parseInt('123')); // 123
console.log(parseInt('123.45')); // 123
console.log(parseInt('123px')); // 123
console.log(parseInt('abc')); // NaN
console.log(parseInt('1010', 2)); // 10 (ikili sistemdən)
// Çıxış:
// 123
// 123
// 123
// NaN
// 10

// parseFloat nümunəsi
console.log(parseFloat('123.45')); // 123.45
console.log(parseFloat('123.45px')); // 123.45
console.log(parseFloat('12.34.56')); // 12.34
console.log(parseFloat('abc')); // NaN
// Çıxış:
// 123.45
// 123.45
// 12.34
// NaN

// toPrecision nümunəsi
const num = 123.456;
console.log(num.toPrecision(5)); // '123.46'
console.log(num.toPrecision(3)); // '123'
console.log(num.toPrecision(2)); // '1.2e+2'
// Çıxış:
// 123.46
// 123
// 1.2e+2

// isNaN nümunəsi
console.log(isNaN(123)); // false
console.log(isNaN('123')); // false
console.log(isNaN('abc')); // true
console.log(isNaN(NaN)); // true
// Çıxış:
// false
// false
// true
// true

// isFinite nümunəsi
console.log(isFinite(123)); // true
console.log(isFinite(Infinity)); // false
console.log(isFinite(-Infinity)); // false
console.log(isFinite(NaN)); // false
// Çıxış:
// true
// false
// false
// false

// Səhvə yol açan nümunə
const price = 19.999;
const formatted = price.toFixed(2); // '20.00'
// console.log(formatted + 10); // '20.0010' (sətir birləşdirilməsi)
const fixedNum = parseFloat(formatted) + 10;
console.log(fixedNum); // 30.00
// Çıxış:
// 30

